[
  {
    "file": "internal/terraform/context_apply.go",
    "line": 153,
    "severity": "critical",
    "description": "Hook return values are not checked. PreApplyImport and PostApplyImport methods return (HookAction, error), but the return values are completely ignored. If a hook returns HookActionHalt, the operation should terminate immediately, but instead execution continues. This is a cross-component interaction bug that breaks the hook dispatch contract.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -150,8 +150,20 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts
 		for _, h := range c.hooks {
 			// In future, we may need to call PostApplyImport separately elsewhere in the apply
 			// operation. For now, though, we'll call Pre and Post hooks together.
-			h.PreApplyImport(hookResourceID, *rc.Importing)
-			h.PostApplyImport(hookResourceID, *rc.Importing)
+			action, err := h.PreApplyImport(hookResourceID, *rc.Importing)
+			if err != nil {
+				diags = diags.Append(err)
+			}
+			if action == HookActionHalt {
+				return nil, nil, diags
+			}
+			action, err = h.PostApplyImport(hookResourceID, *rc.Importing)
+			if err != nil {
+				diags = diags.Append(err)
+			}
+			if action == HookActionHalt {
+				return nil, nil, diags
+			}
 		}
 	}
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 216,
    "severity": "low",
    "description": "Grammatical error in error message. The error message says 'accepting a ephemeral values' but should say 'accepting ephemeral values' (remove the 'a'). This is a minor data integrity issue affecting user-facing error output.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -213,7 +213,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *I
 			diags = diags.Append(&hcl.Diagnostic{
 				Severity: hcl.DiagError,
 				Summary:  "Ephemeral value not allowed",
-				Detail:   "This input variable is not declared as accepting a ephemeral values, so it cannot be set to a result derived from an ephemeral value.",
+				Detail:   "This input variable is not declared as accepting ephemeral values, so it cannot be set to a result derived from an ephemeral value.",
 				Subject:  subject.Ptr(),
 			})
 		}
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 218,
    "severity": "high",
    "description": "Data integrity bug: When an ephemeral value is assigned to a non-ephemeral input variable, an error diagnostic is appended but the value is still returned with the ephemeral mark. This is inconsistent with other error cases in the same function (lines 49, 93, 146) which return cty.UnknownVal(). The ephemeral mark should not propagate past an error condition to prevent downstream misuse.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -211,6 +211,7 @@ func prepareFinalInputVariableValue(addr addrs.AbsInputVariableInstance, raw *I
 			diags = diags.Append(&hcl.Diagnostic{
 				Severity: hcl.DiagError,
 				Summary:  "Ephemeral value not allowed",
 				Detail:   "This input variable is not declared as accepting ephemeral values, so it cannot be set to a result derived from an ephemeral value.",
 				Subject:  subject.Ptr(),
 			})
+			return cty.UnknownVal(cfg.Type), diags
 		}
 	}
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 491,
    "severity": "medium",
    "description": "Copy-paste error in error message. When ephemeral mark is detected in error message value, the message says 'The error message included a sensitive value' but should say 'The error message included an ephemeral value'. This is a functional bug that produces confusing error messages for users.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -488,7 +488,7 @@ func evalVariableValidation(validation *configs.CheckRule, hclCtx *hcl.EvalCont
 				Expression:  validation.ErrorMessage,
 				EvalContext: hclCtx,
 			})
-				errorMessage = "The error message included a sensitive value, so it will not be displayed."
+				errorMessage = "The error message included an ephemeral value, so it will not be displayed."
 			} else {
 				errorMessage = strings.TrimSpace(errorValue.AsString())
 			}
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 200,
    "severity": "medium",
    "description": "Inconsistent error handling in GetForEachAttr. The 'value' case (line 203-211) checks for cty.NilVal and returns an error immediately, while the 'key' case (line 199) does not perform this check. Both cases should behave identically - if either 'key' or 'value' is NilVal (indicating no for_each context), the same specific error should be returned rather than falling through to the generic error at line 222.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -198,8 +198,21 @@ func (d *evaluationStateData) GetForEachAttr(addr addrs.ForEachAttr, rng tfdiags
 	case "key":
 		returnVal = d.InstanceKeyData.EachKey
+		if returnVal == cty.NilVal {
+			diags = diags.Append(&hcl.Diagnostic{
+				Severity: hcl.DiagError,
+				Summary:  `each.key cannot be used in this context`,
+				Detail:   `A reference to "each.key" has been used in a context in which it is unavailable, such as when the configuration no longer contains the value in its "for_each" expression. Remove this reference to each.key in your configuration to work around this error.`,
+				Subject:  rng.ToHCL().Ptr(),
+			})
+			return cty.UnknownVal(cty.DynamicPseudoType), diags
+		}
 	case "value":
 		returnVal = d.InstanceKeyData.EachValue

 		if returnVal == cty.NilVal {
 			diags = diags.Append(&hcl.Diagnostic{
"
  }
]

